                <th scope="col" className="px-6 py-4">เบอร์โทร</th>
                <th scope="col" className="px-6 py-4">สิทธิ์การรักษา</th>
                <th scope="col" className="px-6 py-4">วันนัดหมาย</th>
                <th scope="col" className="px-6 py-4">สถานะ</th>
                <th scope="col" className="px-6 py-4 text-center">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {paginatedPatients.length > 0 ? paginatedPatients.map((patient, index) => {
                // Use strictly calculated status
                const calculatedStatus = calculatePatientStatus(patient);
                return (
                    <tr 
                        key={patient.id} 
                        className="bg-white hover:bg-slate-50 transition-colors opacity-0 animate-fade-in-up"
                        style={{ animationDelay: `${index * 50}ms` }}
                    >
                        <td className="px-6 py-4 font-semibold text-emerald-700">{patient.hn}</td>
                        <td className="px-6 py-4 font-medium text-slate-900">{`${patient.firstName || '-'} ${patient.lastName || ''}`}</td>
                        <td className="px-6 py-4">{calculateAge(patient.dob)}</td>
                        <td className="px-6 py-4 font-mono text-slate-500">{patient.phone || '-'}</td>
                        <td className="px-6 py-4 truncate max-w-[150px]" title={patient.healthcareScheme}>{patient.healthcareScheme || '-'}</td>
                        <td className="px-6 py-4">
                            {patient.nextAppointmentDate ? (
                                <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-blue-50 text-blue-700">
                                    {formatThaiDateShort(patient.nextAppointmentDate)}
                                </span>
                            ) : '-'}
                        </td>
                        <td className="px-6 py-4">{getStatusBadge(calculatedStatus)}</td>
                        <td className="px-6 py-4 text-center">
                            <div className="flex items-center justify-center space-x-3">
                                <button onClick={() => onSelectPatient(patient.id)} className="font-semibold text-emerald-600 hover:text-emerald-800 transition-all hover:scale-105 active:scale-95">
                                    ดูข้อมูล
                                </button>
                                <button 
                                    type="button"
                                    onClick={(e) => { 
                                        e.preventDefault();
                                        e.stopPropagation(); 
                                        onDeletePatient(patient.id); 
                                    }} 
                                    className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-full transition-all hover:rotate-12 active:scale-95"
                                    title="ลบผู้ป่วย"
                                >
                                    <TrashIcon className="h-4 w-4 pointer-events-none" />
                                </button>
                            </div>
                        </td>
                    </tr>
                );
              }) : (
                  <tr>
                      <td colSpan={8} className="px-6 py-16 text-center text-slate-400 bg-slate-50/30">
                          <div className="flex flex-col items-center justify-center animate-pulse">
                              <SearchIcon className="h-10 w-10 text-slate-300 mb-2" />
                              <p>ไม่พบข้อมูลผู้ป่วยที่ตรงกับเงื่อนไข</p>
                          </div>
                      </td>
                  </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* --- Pagination Controls --- */}
        <div className="flex flex-col md:flex-row justify-between items-center px-6 py-4 bg-white border-t border-slate-200">
            <p className="text-sm text-slate-500 mb-4 md:mb-0">
                แสดง <span className="font-semibold text-slate-800">{filteredPatients.length > 0 ? startIndex + 1 : 0}</span> ถึง <span className="font-semibold text-slate-800">{Math.min(startIndex + itemsPerPage, totalPatients)}</span> จาก <span className="font-semibold text-slate-800">{totalPatients}</span> รายการ
            </p>
            <div className="flex items-center space-x-2">
                <button 
                    onClick={() => handlePageChange(currentPage - 1)}
                    disabled={currentPage === 1}
                    className="p-2 rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-slate-600 hover:-translate-x-1"
                >
                    <ChevronLeftIcon />
                </button>

                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                    let pNum = i + 1;
                    if (totalPages > 5 && currentPage > 3) {
                        pNum = currentPage - 2 + i;
                    }
                    if (pNum > totalPages) return null;

                    return (
                         <button 
                            key={pNum}
                            onClick={() => handlePageChange(pNum)}
                            className={`w-8 h-8 rounded-lg text-sm font-medium transition-all duration-200 ${currentPage === pNum ? 'bg-emerald-600 text-white shadow-md shadow-emerald-500/30 scale-110' : 'text-slate-600 hover:bg-slate-100 hover:scale-105'}`}
                        >
                            {pNum}
                        </button>
                    );
                })}

                <button 
                    onClick={() => handlePageChange(currentPage + 1)}
                    disabled={currentPage === totalPages || totalPages === 0}
                    className="p-2 rounded-lg hover:bg-slate-100 disabled:opacity-30 disabled:cursor-not-allowed transition-colors text-slate-600 hover:translate-x-1"
                >
                    <ChevronRightIcon />
                </button>
            </div>
        </div>

      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { labelClass, inputClass } from './utils';
import { ChevronDownIcon } from './icons';

export const HOSPITALS = [
    'โรงพยาบาลกันทรวิชัย',
    'โรงพยาบาลกุดรัง',
    'โรงพยาบาลแกดำ',
    'โรงพยาบาลโกสุมพิสัย',
    'โรงพยาบาลชื่นชม',
    'โรงพยาบาลเชียงยืน',
    'โรงพยาบาลนาเชือก',
    'โรงพยาบาลนาดูน',
    'โรงพยาบาลบรบือ',
    'โรงพยาบาลพยัคฆภูมิพิสัย',
    'โรงพยาบาลยางสีสุราช',
    'โรงพยาบาลวาปีปทุม',
    'โรงพยาบาลสุทธาเวช',
    'โรงพยาบาลร้อยเอ็ด',
    'โรงพยาบาลขอนแก่น',
    'โรงพยาบาลศรีนครินทร์'
];

interface HospitalSearchableSelectProps {
    label: string;
    selectedValue: string;
    onSelect: (value: string) => void;
    placeholder?: string;
}

export const HospitalSearchableSelect: React.FC<HospitalSearchableSelectProps> = ({ 
    label, 
    selectedValue, 
    onSelect, 
    placeholder = "ค้นหาหรือเลือกโรงพยาบาล..." 
}) => {
    const [isOpen, setIsOpen] = useState(false);
    const [searchTerm, setSearchTerm] = useState('');
    const [isManualMode, setIsManualMode] = useState(false);
    const wrapperRef = useRef<HTMLDivElement>(null);

    // ตรวจสอบว่าค่าปัจจุบันคือค่าที่มีในรายการหรือไม่
    const isInList = useMemo(() => HOSPITALS.includes(selectedValue), [selectedValue]);

    useEffect(() => {
        if (selectedValue !== '' && !isInList) {
            setIsManualMode(true);
            setSearchTerm('อื่นๆ ระบุ');
        } else {
            setSearchTerm(selectedValue);
            if (selectedValue !== '') setIsManualMode(false);
        }
    }, [selectedValue, isInList]);

    useEffect(() => {
        function handleClickOutside(event: MouseEvent) {
            if (wrapperRef.current && !wrapperRef.current.contains(event.target as Node)) {
                setIsOpen(false);
                // คืนค่า searchTerm ให้ตรงกับสิ่งที่เลือกอยู่
                setSearchTerm(isManualMode ? 'อื่นๆ ระบุ' : selectedValue);
            }
        }
        document.addEventListener("mousedown", handleClickOutside);
        return () => document.removeEventListener("mousedown", handleClickOutside);
    }, [selectedValue, isManualMode]);

    const options = useMemo(() => [...HOSPITALS, 'อื่นๆ ระบุ'], []);

    const filteredOptions = useMemo(() => {
        if (!searchTerm || searchTerm === selectedValue || (isManualMode && searchTerm === 'อื่นๆ ระบุ')) return options;
        return options.filter(opt => opt.toLowerCase().includes(searchTerm.toLowerCase()));
    }, [options, searchTerm, selectedValue, isManualMode]);

    const handleOptionClick = (opt: string) => {
        if (opt === 'อื่นๆ ระบุ') {
            setIsManualMode(true);
            onSelect(''); // ล้างค่าเดิมเพื่อให้เริ่มกรอกใหม่
        } else {
            setIsManualMode(false);
            onSelect(opt);
        }
        setIsOpen(false);
    };

    return (
        <div className="space-y-2" ref={wrapperRef}>
            <div className="relative">
                <label className={labelClass}>{label}</label>
                <div className="relative mt-1">
                    <input
                        type="text"
                        className={inputClass + " pr-10"}
                        placeholder={placeholder}
                        value={searchTerm}
                        onChange={(e) => {
                            setSearchTerm(e.target.value);
                            setIsOpen(true);
                        }}
                        onFocus={() => setIsOpen(true)}
                        autoComplete="off"
                    />
                    <div className="absolute inset-y-0 right-0 flex items-center pr-3 pointer-events-none">
                        <ChevronDownIcon className="h-4 w-4 text-gray-400" />
                    </div>
                </div>

                {isOpen && (
                    <ul className="absolute z-50 w-full bg-white shadow-xl max-h-60 rounded-xl py-1 text-sm ring-1 ring-black ring-opacity-5 overflow-auto focus:outline-none mt-1 border border-slate-100">
                        {filteredOptions.length === 0 ? (
                            <li className="px-4 py-2 text-slate-400 italic">ไม่พบตัวเลือก</li>
                        ) : (
                            filteredOptions.map((opt, idx) => (
                                <li
                                    key={`${opt}-${idx}`}
                                    className={`cursor-pointer select-none relative py-2.5 px-4 hover:bg-emerald-50 transition-colors ${((opt === 'อื่นๆ ระบุ' && isManualMode) || (opt === selectedValue && !isManualMode)) ? 'bg-emerald-50 text-emerald-700 font-bold' : 'text-slate-700'}`}
                                    onClick={() => handleOptionClick(opt)}
                                >
                                    {opt}
                                </li>
                            ))
                        )}
                    </ul>
                )}
            </div>

            {isManualMode && (
                <div className="animate-in fade-in slide-in-from-top-1 duration-200 p-3 bg-emerald-50/50 rounded-xl border border-emerald-100 ring-1 ring-emerald-500/10">
                    <label className="text-[10px] font-bold text-emerald-600 uppercase mb-1.5 block px-1 tracking-wider">โปรดระบุชื่อโรงพยาบาล</label>
                    <input
                        type="text"
                        className={inputClass + " border-emerald-200 focus:ring-emerald-500/30 focus:border-emerald-500 bg-white"}
                        placeholder="ระบุชื่อโรงพยาบาลที่นี่..."
                        value={selectedValue}
                        onChange={(e) => onSelect(e.target.value)}
                        autoFocus
                    />
                </div>
            )}
        </div>
    );
};

